import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G01: 公司歷史與創辦人研究","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組/G01_公司歷史與創辦人研究_投資研究員.md","filePath":"32Ｑ題本＿重要/經營組/G01_公司歷史與創辦人研究_投資研究員.md"}'),l={name:"32Ｑ題本＿重要/經營組/G01_公司歷史與創辦人研究_投資研究員.md"};function i(n,a,s,_,h,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="g01-公司歷史與創辦人研究" tabindex="-1">G01: 公司歷史與創辦人研究 <a class="header-anchor" href="#g01-公司歷史與創辦人研究" aria-label="Permalink to &quot;G01: 公司歷史與創辦人研究&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G01</li><li>**題目： 公司歷史背景、創辦人及其性格與價值觀為何？對公司目前文化及發展策略有何深層影響？</li></ul><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>創辦人楊超群性格[保守穩健+行銷導向]，帶動公司[適度多元+跟隨客戶]策略。2023年底長子楊奕康接執行長，過渡期尚穩。企業文化底色為「系統化執行力+危機驅動的趨勢追隨」，處守成轉型期，與AI伺服器浪潮重疊。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A (良)</strong>：創辦人意志與組織文化高度統一（「積極、創新、效率」貫穿36年），接班已啟動（楊奕康歷練14年），歷史決策具長線一致性（從未虧損）。扣分：接班僅第二年，楊奕康面臨缺工、海外管理、AI催單擴產等壓力，韌性待驗證。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p>創辦人畫像：楊超群公務員家庭出身，基層業務起家，1990年以60萬創立瀚荃。性格關鍵：危機意識重（「希望領先部署」）、行銷王道、系統化偏執（&lt;20人即導入ERP）、33年不虧損執念，被稱「連接器獲利哥」。價值觀固化三路徑：ERP系統化→成本控管慣性、行銷優先→適度多元產品策略、品牌化反制低價競爭(CviLux)。</p></li><li><p>歷史變革：1990創立→1996切入消費電子成全球最大電源連接器出貨商→1999中國/東南亞布局(7基地/峰值6000人)→2010 IoT投入→2023世代交替→2025-26 AI伺服器電源連接器佔比5%→21%，營收33.35億YoY+6.9%，毛利率31%→39%。最慘一年2023Q4(EPS 0.16)，主因業外損失4.79億侵蝕，本業營業利益率10.4%仍穩健。</p></li><li><p>治理韌性：決策從個人意志→體系慣性過渡中，接班進度約60%。關鍵人風險中等偏高(無外部專業經理人制衡)，目前未見權力鬥爭。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li>楊奕康進取作風(收購全宇昕、結盟戴盟機器人) vs 父親33年「不虧錢」底線有張力；2. 中國vs東南亞產能再平衡時程能否跟上地緣風險；3. IoT新事業前車之鑑，IC設計聯盟磨合風險。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li>EMBA雜誌443期專訪: <a href="https://www.emba.com.tw/?action=news_detail&amp;aID=4906" target="_blank" rel="noreferrer">https://www.emba.com.tw/?action=news_detail&amp;aID=4906</a></li><li>鏡週刊2023/04報導: <a href="https://www.mirrormedia.mg/story/20230406bus004" target="_blank" rel="noreferrer">https://www.mirrormedia.mg/story/20230406bus004</a></li><li>經濟日報2026/04: <a href="https://money.udn.com/money/story/5612/9434596" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5612/9434596</a></li><li>今周刊2023/08: <a href="https://www.businesstoday.com.tw/article/category/183015/post/202308080036/" target="_blank" rel="noreferrer">https://www.businesstoday.com.tw/article/category/183015/post/202308080036/</a></li><li>FinMind finance 8103 2023Q2-2025Q4</li></ol><hr><p><strong>報告寫入路徑</strong>：/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/8103_瀚荃/20260425/經營組/G01_公司歷史與創辦人研究.md <strong>審計身分</strong>：投資研究員 (finance-investment-researcher) | Deep32Q L3 <strong>數據時效</strong>：截至2026年4月25日最新公開數據</p>',14)])])}const m=e(l,[["render",i]]);export{p as __pageData,m as default};
